module top_module(
  input [7:0] A,
  input [7:0] B,
  output [7:0] X
);wire [7:0] temp;

  assign temp = A | B;
  assign X = temp;

  always @(*) begin
    if (1'b0) begin
      X[0] <= ~A[0];
      X[1] <= ~A[1];
      X[2] <= ~A[2];
      X[3] <= ~A[3];
      X[4] <= ~A[4];
      X[5] <= ~A[5];
      X[6] <= ~A[6];
      X[7] <= ~A[7];
    end
  end

endmodule
